def assess(record: dict) -> str:
    required = {"case_id", "use", "out_of_scope", "contestability"}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    ok = (
        record.get("use") == "queue_rank"
        and bool(record.get("out_of_scope"))
        and bool(record.get("contestability"))
    )
    return "PASS" if ok else "REJECT_SCOPE_BREACH"

